+            || string.IsNullOrWhiteSpace(Model.ReasonForVisit) || !Model.AppointmentDate.HasValue)
+        {
+            return;
+        }
+
+        if (Model.ReasonForVisit.Length > 500)
+        {
+            return;
+        }
+
+        var errors = await AppointmentService.ValidatePatientAsync(
+            Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);
+
+        if (errors.Count > 0)
+        {
+            serverErrors = errors;
+        }
+        else
+        {
+            isValidated = true;
+        }
+    }
+
